+    let top_k = options.limit.unwrap_or(100);
+
+    let semantic_hits = if query_vector.is_empty() || query_vector.iter().any(|v| !v.is_finite()) {
+        Vec::new()
+    } else {
+        search_semantic_sync(conn, embedder_id, query_vector, options)?
